class Solution:
    def minAbsDiff(self, grid, k):
        m = len(grid)
        n = len(grid[0])
        res = []
        for i in range(m - k + 1):
            row = []
            for j in range(n - k + 1):
                vals = [grid[i + a][j + b] for a in range(k) for b in range(k)]
                best = None
                for x in range(len(vals)):
                    for y in range(x + 1, len(vals)):
                        if vals[x] != vals[y]:
                            d = abs(vals[x] - vals[y])
                            if best is None or d < best:
                                best = d
                row.append(0 if best is None else best)
            res.append(row)
        return res

