        for i in range(m - k + 1):
            row = []
            for j in range(n - k + 1):
                vals = sorted({grid[i + a][j + b] for a in range(k) for b in range(k)})
                if len(vals) < 2:
                    row.append(0)
                else:
                    best = min(vals[x + 1] - vals[x] for x in range(len(vals) - 1))
                    row.append(best)
            res.append(row)
        return res

