var minAbsDiff = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const res = [];
    for (let i = 0; i + k <= m; i++) {
        const row = [];
        for (let j = 0; j + k <= n; j++) {
            const set = new Set();
            for (let a = 0; a < k; a++)
                for (let b = 0; b < k; b++)
                    set.add(grid[i + a][j + b]);
            const vals = Array.from(set).sort((x, y) => x - y);
            if (vals.length < 2) {
                row.push(0);
            } else {
                let best = Infinity;
                for (let x = 0; x + 1 < vals.length; x++) {
                    const d = vals[x + 1] - vals[x];
                    if (d < best) best = d;
                }
                row.push(best);
            }
        }
        res.push(row);
    }
    return res;
};
